CREATE TABLE "ExportProductName" (
    "id" TEXT NOT NULL,
    "exportCountry" TEXT NOT NULL,
    "productName" TEXT NOT NULL,
    "englishName" TEXT NOT NULL,
    "productCode" TEXT NOT NULL,
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updatedAt" TIMESTAMP(3) NOT NULL,
    "createdById" TEXT,
    "updatedById" TEXT,

    CONSTRAINT "ExportProductName_pkey" PRIMARY KEY ("id")
);

CREATE UNIQUE INDEX "ExportProductName_exportCountry_productName_productCode_key"
ON "ExportProductName"("exportCountry", "productName", "productCode");

CREATE INDEX "ExportProductName_exportCountry_productName_idx"
ON "ExportProductName"("exportCountry", "productName");

CREATE INDEX "ExportProductName_productCode_idx"
ON "ExportProductName"("productCode");

ON CONFLICT ("exportCountry", "productName", "productCode")
DO UPDATE SET "englishName" = EXCLUDED."englishName", "updatedAt" = CURRENT_TIMESTAMP;
